import React, { useState, useEffect, useContext } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { FaHeart, FaRegHeart, FaBookmark, FaRegBookmark, FaShare, FaEdit, FaTrash, FaArrowLeft } from 'react-icons/fa';
import { toast } from 'react-toastify';
import { formatDistanceToNow, format } from 'date-fns';
import { AuthContext } from '../context/AuthContext';
import forumService from '../services/forumService';
import Spinner from '../components/Spinner';
import CommentForm from '../components/CommentForm';
import CommentItem from '../components/CommentItem';

const PostDetail = () => {
  const { postId } = useParams();
  const { user } = useContext(AuthContext);
  const navigate = useNavigate();
  
  const [post, setPost] = useState(null);
  const [loading, setLoading] = useState(true);
  const [comments, setComments] = useState([]);
  const [isLiked, setIsLiked] = useState(false);
  const [isBookmarked, setIsBookmarked] = useState(false);
  const [likeCount, setLikeCount] = useState(0);
  const [commentCount, setCommentCount] = useState(0);
  const [deleteConfirm, setDeleteConfirm] = useState(false);
  
  // Fetch post details and comments
  useEffect(() => {
    const fetchPostDetails = async () => {
      try {
        setLoading(true);
        const postData = await forumService.getPostById(postId);
        setPost(postData);
        setIsLiked(postData.isLiked || false);
        setIsBookmarked(postData.isBookmarked || false);
        setLikeCount(postData.likes || 0);
        
        const commentsData = await forumService.getComments(postId);
        setComments(commentsData);
        setCommentCount(commentsData.length);
      } catch (error) {
        console.error('Error fetching post details:', error);
        toast.error('Failed to load post details');
      } finally {
        setLoading(false);
      }
    };
    
    fetchPostDetails();
  }, [postId]);
  
  // Handle like/unlike
  const handleLikeToggle = async () => {
    if (!user) {
      toast.info('Please log in to like posts');
      return;
    }
    
    try {
      if (isLiked) {
        await forumService.unlikePost(postId);
        setLikeCount(prev => prev - 1);
      } else {
        await forumService.likePost(postId);
        setLikeCount(prev => prev + 1);
      }
      setIsLiked(!isLiked);
    } catch (error) {
      toast.error('Failed to process like action');
      console.error('Like action failed:', error);
    }
  };
  
  // Handle bookmark/unbookmark
  const handleBookmarkToggle = async () => {
    if (!user) {
      toast.info('Please log in to bookmark posts');
      return;
    }
    
    try {
      if (isBookmarked) {
        await forumService.unbookmarkPost(postId);
      } else {
        await forumService.bookmarkPost(postId);
      }
      setIsBookmarked(!isBookmarked);
    } catch (error) {
      toast.error('Failed to process bookmark action');
      console.error('Bookmark action failed:', error);
    }
  };
  
  // Handle share post
  const handleShare = () => {
    if (navigator.share) {
      navigator.share({
        title: post.title,
        text: `Check out this discussion: ${post.title}`,
        url: window.location.href
      })
        .then(() => toast.success('Post shared successfully'))
        .catch((error) => console.error('Error sharing:', error));
    } else {
      // Fallback for browsers that don't support navigator.share
      navigator.clipboard.writeText(window.location.href)
        .then(() => toast.success('Link copied to clipboard'))
        .catch(() => toast.error('Failed to copy link'));
    }
  };
  
  // Handle delete post
  const handleDeletePost = async () => {
    if (!deleteConfirm) {
      setDeleteConfirm(true);
      return;
    }
    
    try {
      setLoading(true);
      await forumService.deletePost(postId);
      toast.success('Post deleted successfully');
      navigate('/forum');
    } catch (error) {
      toast.error('Failed to delete post');
      console.error('Error deleting post:', error);
      setLoading(false);
    }
  };
  
  // Handle add comment
  const handleAddComment = async (comment) => {
    try {
      const newComment = await forumService.addComment(postId, comment);
      setComments(prev => [newComment, ...prev]);
      setCommentCount(prev => prev + 1);
      toast.success('Comment added successfully');
    } catch (error) {
      toast.error('Failed to add comment');
      console.error('Error adding comment:', error);
    }
  };
  
  // Handle delete comment
  const handleDeleteComment = async (commentId) => {
    try {
      await forumService.deleteComment(postId, commentId);
      setComments(prev => prev.filter(comment => comment._id !== commentId));
      setCommentCount(prev => prev - 1);
      toast.success('Comment deleted successfully');
    } catch (error) {
      toast.error('Failed to delete comment');
      console.error('Error deleting comment:', error);
    }
  };
  
  if (loading) {
    return <Spinner />;
  }
  
  if (!post) {
    return (
      <div className="max-w-4xl mx-auto mt-10 p-5">
        <div className="text-center">
          <h2 className="text-2xl font-bold text-red-600">Post not found</h2>
          <p className="mt-2 text-gray-600">The post you're looking for doesn't exist or has been removed.</p>
          <Link to="/forum" className="mt-4 inline-block bg-blue-600 text-white py-2 px-4 rounded hover:bg-blue-700">
            Back to Forum
          </Link>
        </div>
      </div>
    );
  }
  
  return (
    <div className="max-w-4xl mx-auto mt-6 p-5">
      <Link to="/forum" className="inline-flex items-center text-blue-600 hover:text-blue-800 mb-4">
        <FaArrowLeft className="mr-2" /> Back to Forum
      </Link>
      
      <div className="bg-white dark:bg-gray-800 rounded-lg shadow-md overflow-hidden">
        {/* Post Header */}
        <div className="p-6 border-b border-gray-200 dark:border-gray-700">
          <div className="flex justify-between items-start">
            <h1 className="text-2xl font-bold text-gray-900 dark:text-white">{post.title}</h1>
            <span className="bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-300 px-2 py-1 rounded text-xs">
              {post.category}
            </span>
          </div>
          
          <div className="flex items-center mt-3">
            <img 
              src={post.author?.profilePicture || 'https://via.placeholder.com/40'} 
              alt={post.author?.name || 'User'} 
              className="w-10 h-10 rounded-full mr-3" 
            />
            <div>
              <p className="font-medium text-gray-800 dark:text-gray-200">{post.author?.name || 'Anonymous'}</p>
              <p className="text-sm text-gray-500 dark:text-gray-400">
                Posted {format(new Date(post.createdAt), 'PPP')} ({formatDistanceToNow(new Date(post.createdAt), { addSuffix: true })})
              </p>
            </div>
          </div>
        </div>
        
        {/* Post Content */}
        <div className="p-6">
          <div className="prose prose-lg max-w-none text-gray-800 dark:text-gray-200">
            <p>{post.description}</p>
          </div>
          
          {post.image && (
            <div className="mt-4">
              <img 
                src={post.image} 
                alt={post.title} 
                className="w-full max-h-96 object-contain rounded border border-gray-200 dark:border-gray-700" 
              />
            </div>
          )}
          
          {/* Post Actions */}
          <div className="flex justify-between items-center mt-6 pt-4 border-t border-gray-200 dark:border-gray-700">
            <div className="flex space-x-4">
              <button 
                onClick={handleLikeToggle} 
                className="flex items-center text-gray-600 dark:text-gray-400 hover:text-red-500 dark:hover:text-red-400"
              >
                {isLiked ? (
                  <FaHeart className="text-red-500 mr-1" />
                ) : (
                  <FaRegHeart className="mr-1" />
                )}
                <span>{likeCount}</span>
              </button>
              
              <button 
                onClick={handleBookmarkToggle}
                className="text-gray-600 dark:text-gray-400 hover:text-blue-500 dark:hover:text-blue-400"
              >
                {isBookmarked ? (
                  <FaBookmark className="text-blue-500" />
                ) : (
                  <FaRegBookmark />
                )}
              </button>
              
              <button 
                onClick={handleShare}
                className="text-gray-600 dark:text-gray-400 hover:text-blue-500 dark:hover:text-blue-400"
              >
                <FaShare />
              </button>
            </div>
            
            {user && post.author?._id === user._id && (
              <div className="flex space-x-2">
                <Link 
                  to={`/forum/edit/${post._id}`} 
                  className="text-gray-600 dark:text-gray-400 hover:text-blue-500 dark:hover:text-blue-400"
                >
                  <FaEdit />
                </Link>
                <button 
                  onClick={handleDeletePost}
                  className={`text-gray-600 dark:text-gray-400 hover:text-red-500 dark:hover:text-red-400 ${deleteConfirm ? 'text-red-500 dark:text-red-400' : ''}`}
                >
                  <FaTrash />
                </button>
              </div>
            )}
          </div>
        </div>
        
        {/* Comments Section */}
        <div className="p-6 bg-gray-50 dark:bg-gray-900">
          <h3 className="text-xl font-semibold mb-4 text-gray-800 dark:text-white">
            Comments ({commentCount})
          </h3>
          
          {user ? (
            <CommentForm onAddComment={handleAddComment} />
          ) : (
            <div className="mb-4 p-3 bg-blue-50 dark:bg-blue-900 text-blue-700 dark:text-blue-200 rounded">
              <p>Please <Link to="/login" className="font-bold underline">log in</Link> to add a comment.</p>
            </div>
          )}
          
          <div className="mt-6 space-y-4">
            {comments.length > 0 ? (
              comments.map(comment => (
                <CommentItem 
                  key={comment._id} 
                  comment={comment} 
                  onDelete={handleDeleteComment} 
                  currentUserId={user?._id}
                />
              ))
            ) : (
              <p className="text-gray-500 dark:text-gray-400">No comments yet. Be the first to comment!</p>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default PostDetail;
